import { describe, it, expect, beforeEach } from 'vitest';
import {
  createGameState,
  createPlayer,
  createUnit,
  createUnitInstance,
  createBoard,
  resetIdCounter,
} from '../factories.js';
import {
  startTurn,
  advancePhase,
  processMove,
  processAbility,
  processAttack,
  endTurn,
  deployReserve,
  checkReserveLocks,
} from '../../src/engines/turn/index.js';
import {
  TurnPhase,
  GamePhase,
} from '../../src/types/index.js';
import type { GameState, UnitInstance, Position } from '../../src/types/index.js';
import { placeUnit } from '../../src/engines/board/index.js';

function setupGameInProgress(): GameState {
  const unit1 = createUnit({ id: 'u1', atk: 3, hp: 10, maxHp: 10, movement: 2, range: 1, cost: 5 });
  const unit2 = createUnit({ id: 'u2', atk: 2, hp: 8, maxHp: 8, movement: 2, range: 1, cost: 5 });
  const unit3 = createUnit({ id: 'u3', atk: 4, hp: 6, maxHp: 6, movement: 1, range: 1, cost: 5 });
  const unit4 = createUnit({ id: 'u4', atk: 3, hp: 7, maxHp: 7, movement: 2, range: 1, cost: 5 });
  const unit5 = createUnit({ id: 'u5', atk: 2, hp: 9, maxHp: 9, movement: 2, range: 1, cost: 5 });
  const unit6 = createUnit({ id: 'u6', atk: 5, hp: 5, maxHp: 5, movement: 1, range: 1, cost: 5 });

  const p1Units: UnitInstance[] = [
    createUnitInstance({ card: unit1, currentHp: 10, ownerId: 'p1', position: { x: 0, y: 0 } }),
    createUnitInstance({ card: unit2, currentHp: 8, ownerId: 'p1', position: { x: 1, y: 0 } }),
    createUnitInstance({ card: unit3, currentHp: 6, ownerId: 'p1', position: { x: 2, y: 0 } }),
  ];

  const p2Units: UnitInstance[] = [
    createUnitInstance({ card: unit4, currentHp: 7, ownerId: 'p2', position: { x: 0, y: 29 } }),
    createUnitInstance({ card: unit5, currentHp: 9, ownerId: 'p2', position: { x: 1, y: 29 } }),
    createUnitInstance({ card: unit6, currentHp: 5, ownerId: 'p2', position: { x: 2, y: 29 } }),
  ];

  const p1 = createPlayer({
    id: 'p1',
    life: 24,
    isReady: true,
    units: p1Units,
    team: {
      activeUnits: [unit1, unit2, unit3],
      reserveUnits: [],
      locked: true,
    },
  });

  const p2 = createPlayer({
    id: 'p2',
    life: 24,
    isReady: true,
    units: p2Units,
    team: {
      activeUnits: [unit4, unit5, unit6],
      reserveUnits: [],
      locked: true,
    },
  });

  let board = createBoard();
  for (const u of p1Units) {
    if (u.position) {
      const r = placeUnit(board, u.card.id, u.position);
      if (r.ok) board = r.value;
    }
  }
  for (const u of p2Units) {
    if (u.position) {
      const r = placeUnit(board, u.card.id, u.position);
      if (r.ok) board = r.value;
    }
  }

  return createGameState({
    phase: GamePhase.IN_PROGRESS,
    turnPhase: TurnPhase.MOVE,
    currentPlayerIndex: 0,
    players: [p1, p2],
    board,
    turnNumber: 1,
    turnRotation: 0,
    movesUsedThisTurn: 0,
  });
}

describe('TurnEngine', () => {
  beforeEach(() => {
    resetIdCounter();
  });

  describe('startTurn', () => {
    it('returns state in MOVE phase for current player', () => {
      const state = setupGameInProgress();
      const result = startTurn(state);
      expect(result.turnPhase).toBe(TurnPhase.MOVE);
      expect(result.movesUsedThisTurn).toBe(0);
    });
  });

  describe('advancePhase', () => {
    it('MOVE → ABILITY — valid', () => {
      const state = setupGameInProgress();
      const result = advancePhase(state);
      expect(result.ok).toBe(true);
      if (result.ok) {
        expect(result.value.turnPhase).toBe(TurnPhase.ABILITY);
      }
    });

    it('ABILITY → ATTACK — valid', () => {
      const state = { ...setupGameInProgress(), turnPhase: TurnPhase.ABILITY };
      const result = advancePhase(state);
      expect(result.ok).toBe(true);
      if (result.ok) {
        expect(result.value.turnPhase).toBe(TurnPhase.ATTACK);
      }
    });

    it('ATTACK → END — valid', () => {
      const state = { ...setupGameInProgress(), turnPhase: TurnPhase.ATTACK };
      const result = advancePhase(state);
      expect(result.ok).toBe(true);
      if (result.ok) {
        expect(result.value.turnPhase).toBe(TurnPhase.END);
      }
    });

    it('END phase — cannot advance further (use endTurn)', () => {
      const state = { ...setupGameInProgress(), turnPhase: TurnPhase.END };
      const result = advancePhase(state);
      expect(result.ok).toBe(false);
    });
  });

  describe('processMove', () => {
    it('valid unit and target — unit moves, move count incremented', () => {
      const state = setupGameInProgress();
      const result = processMove(state, 'p1', 'u1', { x: 0, y: 1 });
      expect(result.ok).toBe(true);
      if (result.ok) {
        expect(result.value.movesUsedThisTurn).toBe(1);
      }
    });

    it('3 moves already used — returns error', () => {
      const state = { ...setupGameInProgress(), movesUsedThisTurn: 3 };
      const result = processMove(state, 'p1', 'u1', { x: 0, y: 1 });
      expect(result.ok).toBe(false);
      if (!result.ok) {
        expect(result.error).toContain('maximum');
      }
    });

    it('unit not owned by current player — returns error', () => {
      const state = setupGameInProgress();
      const result = processMove(state, 'p1', 'u4', { x: 0, y: 28 });
      expect(result.ok).toBe(false);
      if (!result.ok) {
        expect(result.error).toContain('own');
      }
    });

    it('not in MOVE phase — returns error', () => {
      const state = { ...setupGameInProgress(), turnPhase: TurnPhase.ATTACK };
      const result = processMove(state, 'p1', 'u1', { x: 0, y: 1 });
      expect(result.ok).toBe(false);
      if (!result.ok) {
        expect(result.error).toContain('MOVE');
      }
    });
  });

  describe('processAbility', () => {
    it('valid ability use — resolves and tracks usage', () => {
      const base = { ...setupGameInProgress(), turnPhase: TurnPhase.ABILITY };
      // Place p2's u4 adjacent to p1's u1 so it's within range 1
      const p2 = base.players[1]!;
      const adjUnits = p2.units.map((u: UnitInstance) =>
        u.card.id === 'u4' ? { ...u, position: { x: 0, y: 1 } as Position } : u
      );
      const board2 = { ...base.board };
      board2.cells = base.board.cells.map((row: any, y: number) =>
        row.map((cell: any, x: number) => {
          if (x === 0 && y === 29) return { ...cell, occupantId: null };
          if (x === 0 && y === 1) return { ...cell, occupantId: 'u4' };
          return cell;
        })
      );
      const finalState = {
        ...base,
        players: [base.players[0]!, { ...p2, units: adjUnits }],
        board: board2,
      };
      const result = processAbility(finalState, 'p1', 'u1', 'u4');
      expect(result.ok).toBe(true);
      if (result.ok) {
        const unit = result.value.players[0]!.units.find((u: UnitInstance) => u.card.id === 'u1');
        expect(unit?.hasUsedAbilityThisTurn).toBe(true);
      }
    });

    it('ability already used this turn — returns error', () => {
      const base = { ...setupGameInProgress(), turnPhase: TurnPhase.ABILITY };
      // Place p2's u4 adjacent to p1's u1 so range check passes
      const p1 = base.players[0]!;
      const p2 = base.players[1]!;
      const adjP2Units = p2.units.map((u: UnitInstance) =>
        u.card.id === 'u4' ? { ...u, position: { x: 0, y: 1 } as Position } : u
      );
      const updatedP1Units = p1.units.map((u: UnitInstance) =>
        u.card.id === 'u1' ? { ...u, hasUsedAbilityThisTurn: true } : u
      );
      const board2 = { ...base.board };
      board2.cells = base.board.cells.map((row: any, y: number) =>
        row.map((cell: any, x: number) => {
          if (x === 0 && y === 29) return { ...cell, occupantId: null };
          if (x === 0 && y === 1) return { ...cell, occupantId: 'u4' };
          return cell;
        })
      );
      const updatedState = {
        ...base,
        players: [{ ...p1, units: updatedP1Units }, { ...p2, units: adjP2Units }],
        board: board2,
      };

      const result = processAbility(updatedState, 'p1', 'u1', 'u4');
      expect(result.ok).toBe(false);
      if (!result.ok) {
        expect(result.error).toContain('already used');
      }
    });

    it('not in ABILITY phase — returns error', () => {
      const state = { ...setupGameInProgress(), turnPhase: TurnPhase.MOVE };
      const result = processAbility(state, 'p1', 'u1', 'u4');
      expect(result.ok).toBe(false);
      if (!result.ok) {
        expect(result.error).toContain('ABILITY');
      }
    });

    it('damage ability kills target — unit removed from board and player units', () => {
      const base = { ...setupGameInProgress(), turnPhase: TurnPhase.ABILITY };
      const p2 = base.players[1]!;
      // Place enemy adjacent and set HP low enough to be killed by DAMAGE (3 dmg)
      const adjP2Units = p2.units.map((u: UnitInstance) =>
        u.card.id === 'u4' ? { ...u, position: { x: 0, y: 1 } as Position, currentHp: 2 } : u
      );
      const board2 = { ...base.board };
      board2.cells = base.board.cells.map((row: any, y: number) =>
        row.map((cell: any, x: number) => {
          if (x === 0 && y === 29) return { ...cell, occupantId: null };
          if (x === 0 && y === 1) return { ...cell, occupantId: 'u4' };
          return cell;
        })
      );
      const state = {
        ...base,
        players: [base.players[0]!, { ...p2, units: adjP2Units }],
        board: board2,
      };

      const result = processAbility(state, 'p1', 'u1', 'u4');
      expect(result.ok).toBe(true);
      if (result.ok) {
        // Target unit should be removed from player 2's unit array
        const p2Units = result.value.players[1]!.units;
        expect(p2Units.find((u: UnitInstance) => u.card.id === 'u4')).toBeUndefined();
        // Board cell should be cleared
        expect(result.value.board.cells[1]![0]!.occupantId).toBeNull();
      }
    });

    it('damage ability reduces HP but does not kill — unit remains', () => {
      const base = { ...setupGameInProgress(), turnPhase: TurnPhase.ABILITY };
      const p2 = base.players[1]!;
      // Place enemy adjacent with enough HP to survive (7 HP, 3 dmg = 4 HP remaining)
      const adjP2Units = p2.units.map((u: UnitInstance) =>
        u.card.id === 'u4' ? { ...u, position: { x: 0, y: 1 } as Position } : u
      );
      const board2 = { ...base.board };
      board2.cells = base.board.cells.map((row: any, y: number) =>
        row.map((cell: any, x: number) => {
          if (x === 0 && y === 29) return { ...cell, occupantId: null };
          if (x === 0 && y === 1) return { ...cell, occupantId: 'u4' };
          return cell;
        })
      );
      const state = {
        ...base,
        players: [base.players[0]!, { ...p2, units: adjP2Units }],
        board: board2,
      };

      const result = processAbility(state, 'p1', 'u1', 'u4');
      expect(result.ok).toBe(true);
      if (result.ok) {
        // Target unit should still exist with reduced HP
        const target = result.value.players[1]!.units.find((u: UnitInstance) => u.card.id === 'u4');
        expect(target).toBeDefined();
        expect(target!.currentHp).toBe(4); // 7 - 3 = 4
        // Board cell should still have the unit
        expect(result.value.board.cells[1]![0]!.occupantId).toBe('u4');
      }
    });
  });

  describe('processAttack', () => {
    it('valid attack — resolves combat, marks unit as acted', () => {
      const state = setupGameInProgress();
      // Place attacker adjacent to defender
      const p1 = state.players[0]!;
      const p2 = state.players[1]!;
      const updatedP1Units = p1.units.map((u: UnitInstance) =>
        u.card.id === 'u1' ? { ...u, position: { x: 0, y: 28 } as Position } : u
      );
      let board = createBoard();
      // Place all units on the board
      for (const u of updatedP1Units) {
        if (u.position) {
          const r = placeUnit(board, u.card.id, u.position);
          if (r.ok) board = r.value;
        }
      }
      for (const u of p2.units) {
        if (u.position) {
          const r = placeUnit(board, u.card.id, u.position);
          if (r.ok) board = r.value;
        }
      }
      const attackState = {
        ...state,
        turnPhase: TurnPhase.ATTACK,
        players: [{ ...p1, units: updatedP1Units }, p2],
        board,
      };

      const result = processAttack(attackState, 'p1', 'u1', 'u4');
      expect(result.ok).toBe(true);
      if (result.ok) {
        const unit = result.value.players[0]!.units.find((u: UnitInstance) => u.card.id === 'u1');
        expect(unit?.hasAttackedThisTurn).toBe(true);
      }
    });

    it('unit already attacked this turn — returns error', () => {
      const state = { ...setupGameInProgress(), turnPhase: TurnPhase.ATTACK };
      const p1 = state.players[0]!;
      const updatedUnits = p1.units.map((u: UnitInstance) =>
        u.card.id === 'u1' ? { ...u, hasAttackedThisTurn: true } : u
      );
      const updatedState = {
        ...state,
        players: [{ ...p1, units: updatedUnits }, state.players[1]!],
      };

      const result = processAttack(updatedState, 'p1', 'u1', 'u4');
      expect(result.ok).toBe(false);
      if (!result.ok) {
        expect(result.error).toContain('already attacked');
      }
    });

    it('not in ATTACK phase — returns error', () => {
      const state = { ...setupGameInProgress(), turnPhase: TurnPhase.MOVE };
      const result = processAttack(state, 'p1', 'u1', 'u4');
      expect(result.ok).toBe(false);
      if (!result.ok) {
        expect(result.error).toContain('ATTACK');
      }
    });

    it('shared card ID across 2 players — only updates correct player units', () => {
      const sharedCard = createUnit({ id: 'shared-u', atk: 3, hp: 10, maxHp: 10, movement: 2, range: 1, cost: 5 });
      const p1Unit = createUnitInstance({ card: sharedCard, currentHp: 10, ownerId: 'p1', position: { x: 0, y: 28 } });
      const p2Unit = createUnitInstance({ card: sharedCard, currentHp: 10, ownerId: 'p2', position: { x: 0, y: 29 } });

      const p1 = createPlayer({ id: 'p1', life: 24, isReady: true, units: [p1Unit], team: { activeUnits: [sharedCard], reserveUnits: [], locked: true } });
      const p2 = createPlayer({ id: 'p2', life: 24, isReady: true, units: [p2Unit], team: { activeUnits: [sharedCard], reserveUnits: [], locked: true } });

      let board = createBoard();
      const r1 = placeUnit(board, 'p1-shared-u', { x: 0, y: 28 });
      if (r1.ok) board = r1.value;
      const r2 = placeUnit(board, 'p2-shared-u', { x: 0, y: 29 });
      if (r2.ok) board = r2.value;

      const state: GameState = {
        ...setupGameInProgress(),
        turnPhase: TurnPhase.ATTACK,
        players: [p1, p2],
        board,
        currentPlayerIndex: 0,
      };

      const result = processAttack(state, 'p1', 'shared-u', 'shared-u', 'p2');
      expect(result.ok).toBe(true);
      if (result.ok) {
        const p1Unit = result.value.players[0]!.units.find((u: UnitInstance) => u.card.id === 'shared-u');
        expect(p1Unit).toBeDefined();
        expect(p1Unit!.currentHp).toBe(7); // 10 - 3 counter
        expect(p1Unit!.hasAttackedThisTurn).toBe(true);

        const p2Unit = result.value.players[1]!.units.find((u: UnitInstance) => u.card.id === 'shared-u');
        expect(p2Unit).toBeDefined();
        expect(p2Unit!.currentHp).toBe(7); // 10 - 3 attack
        expect(p2Unit!.hasAttackedThisTurn).toBe(false);
      }
    });

    it('shared card ID across 3 players — defenderOwnerId targets correct player', () => {
      const sharedCard = createUnit({ id: 'shared-u', atk: 3, hp: 10, maxHp: 10, movement: 2, range: 1, cost: 5 });
      const p1Unit = createUnitInstance({ card: sharedCard, currentHp: 10, ownerId: 'p1', position: { x: 0, y: 28 } });
      const p2Unit = createUnitInstance({ card: sharedCard, currentHp: 10, ownerId: 'p2', position: { x: 0, y: 29 } });
      const p3Unit = createUnitInstance({ card: sharedCard, currentHp: 10, ownerId: 'p3', position: { x: 1, y: 29 } });

      const p1 = createPlayer({ id: 'p1', life: 24, isReady: true, units: [p1Unit], team: { activeUnits: [sharedCard], reserveUnits: [], locked: true } });
      const p2 = createPlayer({ id: 'p2', life: 24, isReady: true, units: [p2Unit], team: { activeUnits: [sharedCard], reserveUnits: [], locked: true } });
      const p3 = createPlayer({ id: 'p3', life: 24, isReady: true, units: [p3Unit], team: { activeUnits: [sharedCard], reserveUnits: [], locked: true } });

      let board = createBoard();
      let r = placeUnit(board, 'p1-shared-u', { x: 0, y: 28 });
      if (r.ok) board = r.value;
      r = placeUnit(board, 'p2-shared-u', { x: 0, y: 29 });
      if (r.ok) board = r.value;
      r = placeUnit(board, 'p3-shared-u', { x: 1, y: 29 });
      if (r.ok) board = r.value;

      const state: GameState = {
        ...setupGameInProgress(),
        turnPhase: TurnPhase.ATTACK,
        players: [p1, p2, p3],
        board,
        currentPlayerIndex: 0,
      };

      // Attack p3's unit specifically using defenderOwnerId
      const result = processAttack(state, 'p1', 'shared-u', 'shared-u', 'p3');
      expect(result.ok).toBe(true);
      if (result.ok) {
        // Attacker (p1) takes counter damage
        const resultP1 = result.value.players[0]!.units.find((u: UnitInstance) => u.card.id === 'shared-u');
        expect(resultP1!.currentHp).toBe(7);
        expect(resultP1!.hasAttackedThisTurn).toBe(true);

        // p2's unit should be UNTOUCHED
        const resultP2 = result.value.players[1]!.units.find((u: UnitInstance) => u.card.id === 'shared-u');
        expect(resultP2!.currentHp).toBe(10);
        expect(resultP2!.hasAttackedThisTurn).toBe(false);

        // p3's unit should have taken damage
        const resultP3 = result.value.players[2]!.units.find((u: UnitInstance) => u.card.id === 'shared-u');
        expect(resultP3!.currentHp).toBe(7);
        expect(resultP3!.hasAttackedThisTurn).toBe(false);
      }
    });
  });

  describe('endTurn', () => {
    it('advances to next player', () => {
      const state = { ...setupGameInProgress(), turnPhase: TurnPhase.END };
      const result = endTurn(state);
      expect(result.ok).toBe(true);
      if (result.ok) {
        expect(result.value.currentPlayerIndex).toBe(1);
        expect(result.value.turnPhase).toBe(TurnPhase.MOVE);
      }
    });

    it('last player in rotation — wraps to first player, increments rotation', () => {
      const state = {
        ...setupGameInProgress(),
        turnPhase: TurnPhase.END,
        currentPlayerIndex: 1,
        turnRotation: 0,
      };
      const result = endTurn(state);
      expect(result.ok).toBe(true);
      if (result.ok) {
        expect(result.value.currentPlayerIndex).toBe(0);
        expect(result.value.turnRotation).toBe(1);
        expect(result.value.turnNumber).toBe(2);
      }
    });
  });

  describe('reserve deployment', () => {
    it('unit died during opponent turn — reserve available', () => {
      const reserveUnit = createUnit({ id: 'r1', cost: 3 });
      const state = setupGameInProgress();
      const p1 = {
        ...state.players[0]!,
        units: state.players[0]!.units.slice(0, 2), // simulate 1 unit died
        team: {
          ...state.players[0]!.team,
          reserveUnits: [reserveUnit],
        },
        reserveLockedUntilNextTurn: false,
      };
      const updatedState = {
        ...state,
        players: [p1, state.players[1]!],
        turnPhase: TurnPhase.MOVE,
        currentPlayerIndex: 0,
      };

      const result = deployReserve(updatedState, 'p1', 'r1', { x: 3, y: 0 });
      expect(result.ok).toBe(true);
    });

    it('unit died during owner turn — reserve locked', () => {
      const reserveUnit = createUnit({ id: 'r1', cost: 3 });
      const state = setupGameInProgress();
      const p1 = {
        ...state.players[0]!,
        team: {
          ...state.players[0]!.team,
          reserveUnits: [reserveUnit],
        },
        reserveLockedUntilNextTurn: true,
      };
      const updatedState = {
        ...state,
        players: [p1, state.players[1]!],
        turnPhase: TurnPhase.MOVE,
        currentPlayerIndex: 0,
      };

      const result = deployReserve(updatedState, 'p1', 'r1', { x: 3, y: 0 });
      expect(result.ok).toBe(false);
      if (!result.ok) {
        expect(result.error).toContain('locked');
      }
    });

    it('no reserves available — returns error', () => {
      const state = setupGameInProgress();
      const result = deployReserve(state, 'p1', 'r1', { x: 3, y: 0 });
      expect(result.ok).toBe(false);
    });
  });

  describe('checkReserveLocks', () => {
    it('new turn starts — clears locks from previous turn', () => {
      const state = setupGameInProgress();
      const p1 = { ...state.players[0]!, reserveLockedUntilNextTurn: true };
      const updatedState = {
        ...state,
        players: [p1, state.players[1]!],
      };

      const result = checkReserveLocks(updatedState, 'p1');
      expect(result.players[0]!.reserveLockedUntilNextTurn).toBe(false);
    });
  });
});
